  const capKey = kind === "rect" ? "rectCapacity" : "glyphCapacity";
  const vaoKey = kind === "rect" ? "rectVao" : "glyphVao";
  if (byteLength <= state[capKey])
    return;
  const newSize = Math.max(byteLength, state[capKey] * 2, 1024);
