          const metrics = widthMap?.get(glyph.glyphId) ?? atlas.glyphs.get(glyph.glyphId);
          if (!metrics)
            continue;
          const applySymbolLayout = symbolLike && (fontIndex > 0 || symbolConstraint || colorGlyph);
