        const searchFg = resolveHighlightForegroundColor(searchHighlightKind === 2 ? searchCurrentMatchTextColor : searchMatchTextColor, fg, bg, inverse);
        pushRect2(selectionData, x3, rowY, cellW, cellH, searchBg);
