        xPad,
        fg,
        bg: bgForText,
        shaped,
        fontIndex,
        scale: fontScale,
        cellWidth: cellWidthPx,
        symbolLike,
        symbolConstraint,
        constraintWidth,
        forceFit,
        glyphWidthPx,
        cp,
        italic,
        bold
