    const fade2 = resizeAge <= RESIZE_OVERLAY_HOLD_MS ? 1 : 1 - (resizeAge - RESIZE_OVERLAY_HOLD_MS) / RESIZE_OVERLAY_FADE_MS;
    const alpha = clamp2(fade2, 0, 1);
